298→func convertErrorInfo(e *instrument.ErrorInfo) *ErrorInfo {
299→	if e == nil {
300→		return nil
301→	}
302→	var stack *string
303→	if e.Stack != "" {
304→		stack = &e.Stack
305→	}
306→	return &ErrorInfo{
307→		ErrorType: e.ErrorType,
308→		Message:   e.Message,
309→		Stack:     stack,
310→	}
311→}
312→
313→func toIntSlice(ints []int) []int {
314→	if ints == nil {
315→		return []int{}
316→	}
317→	return ints
318→}
319→
320→func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
321→	result := make([]BranchDecision, len(branches))
322→	for i, b := range branches {
323→		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
324→		if b.ConstraintJSON != "" {
325→			var sc SymConstraint
326→			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
327→				constraint = &sc
328→			}
329→		}
330→		result[i] = BranchDecision{
331→			BranchID:   b.BranchID,
332→			Line:       b.Line,
333→			Taken:      b.Taken,
334→			Constraint: constraint,
335→		}
336→	}
337→	return result
338→}
339→
340→func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
341→	var constraints []SymConstraint
342→	for _, b := range branches {
343→		if b.ConstraintJSON == "" {
344→			continue
345→		}
346→		var sc SymConstraint
347→		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
348→			constraints = append(constraints, sc)
349→		}
350→	}
351→	if constraints == nil {
352→		return []SymConstraint{}
353→	}
354→	return constraints
355→}
356→
357→// convertExternalCalls converts executor ExternalCall records to protocol format.
358→func convertExternalCalls(calls []instrument.ExternalCall) []ExternalCall {
359→	if len(calls) == 0 {
360→		return []ExternalCall{}
361→	}
362→	result := make([]ExternalCall, len(calls))
363→	for i, c := range calls {
364→		var args []any
365→		if c.Args != nil {
366→			json.Unmarshal(c.Args, &args) //nolint:errcheck
367→		}
368→		var retVal any
369→		if c.ReturnValue != nil {
370→			json.Unmarshal(c.ReturnValue, &retVal) //nolint:errcheck
371→		}
372→		result[i] = ExternalCall{
373→			Symbol:      c.Symbol,
374→			Args:        args,
375→			ReturnValue: retVal,
376→		}
377→	}
378→	return result
379→}
380→
381→// convertSideEffects converts executor SideEffects to protocol format.
382→func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
383→	if len(effects) == 0 {
384→		return []SideEffect{}
385→	}
386→	result := make([]SideEffect, len(effects))
387→	for i, e := range effects {
388→		result[i] = SideEffect{
389→			Kind:    e.Kind,
390→			Level:   e.Level,
391→			Message: e.Message,
392→		}
393→	}
394→	return result
395→}
