830→// TestConvertSideEffects verifies that instrument.SideEffect values are
831→// correctly mapped to protocol SideEffect values with the right JSON field
832→// names (kind, not type) and snake_case values (console_output, not ConsoleOutput).
833→// TestExecuteAfterInstrumentWithoutAnalyze verifies the scan flow:
834→// Instrument (with file) → Execute (without file) succeeds because
835→// handleInstrument sets lastAnalyzedFile.
836→func TestExecuteAfterInstrumentWithoutAnalyze(t *testing.T) {
837→	tmp := filepath.Join(t.TempDir(), "target.go")
838→	src := `package main
839→
840→func double(x int) int {
841→	return x * 2
842→}
843→`
844→	if err := os.WriteFile(tmp, []byte(src), 0644); err != nil {
845→		t.Fatal(err)
846→	}
847→	responses := conversation(t,
848→		reqJSON(1, "handshake", `"capabilities":["instrument","execute"]`),
849→		reqJSON(2, "instrument", fmt.Sprintf(`"file":"%s","function":"double"`, tmp)),
850→		reqJSON(3, "execute", `"function":"double","inputs":[5],"mocks":[]`),
851→		reqJSON(4, "shutdown"),
852→	)
853→	if len(responses) != 4 {
854→		t.Fatalf("got %d responses, want 4", len(responses))
855→	}
856→	if responses[1].Status != "instrument" {
857→		t.Fatalf("instrument: status = %q, want instrument (message: %s)", responses[1].Status, responses[1].Message)
858→	}
859→	if responses[2].Status != "execute" {
860→		t.Fatalf("execute: status = %q, want execute (message: %s)", responses[2].Status, responses[2].Message)
861→	}
862→	var retVal int
863→	if err := json.Unmarshal(responses[2].ReturnValue, &retVal); err != nil {
864→		t.Fatalf("parsing return value: %v", err)
865→	}
866→	if retVal != 10 {
867→		t.Errorf("expected return value 10, got %d", retVal)
868→	}
869→	// Cleanup instrumented output
870→	if responses[1].OutputFile != nil {
871→		os.RemoveAll(*responses[1].OutputFile)
872→	}
873→}
