 64→func genBranchInfo() *rapid.Generator[BranchInfo] {
 65→	return rapid.Custom[BranchInfo](func(t *rapid.T) BranchInfo {
 66→		return BranchInfo{
 67→			ID:            rapid.IntRange(0, 100).Draw(t, "id"),
 68→			Line:          rapid.IntRange(1, 500).Draw(t, "line"),
 69→			ConditionText: rapid.StringMatching(`.{0,20}`).Draw(t, "cond"),
 70→			Condition:     nil,
 71→			BranchType:    rapid.SampledFrom([]string{"if", "else_if", "switch", "ternary", "logical_and", "logical_or", "while", "for"}).Draw(t, "bt"),
 72→		}
 73→	})
 74→}
