 76→func genFunctionAnalysis() *rapid.Generator[FunctionAnalysis] {
 77→	return rapid.Custom[FunctionAnalysis](func(t *rapid.T) FunctionAnalysis {
 78→		startLine := rapid.IntRange(1, 500).Draw(t, "start")
 79→		endLine := rapid.IntRange(startLine, startLine+200).Draw(t, "end")
 80→		return FunctionAnalysis{
 81→			Name:         genIdent().Draw(t, "name"),
 82→			Exported:     rapid.Bool().Draw(t, "exported"),
 83→			Params:       rapid.SliceOfN(genParamInfo(), 0, 4).Draw(t, "params"),
 84→			Branches:     rapid.SliceOfN(genBranchInfo(), 0, 4).Draw(t, "branches"),
 85→			Dependencies: []ExternalDependency{},
