const ProtocolVersion = "0.1.0"

// SetupLevel represents the granularity level for setup/teardown lifecycle management.
// Matches the Rust core's SetupLevel enum (serde rename_all = "snake_case").
type SetupLevel string

const (
	SetupLevelSession   SetupLevel = "session"
	SetupLevelFile      SetupLevel = "file"
	SetupLevelFunction  SetupLevel = "function"
	SetupLevelExecution SetupLevel = "execution"
)

// ValidSetupLevels lists all valid SetupLevel values.
var ValidSetupLevels = []SetupLevel{
	SetupLevelSession,
	SetupLevelFile,
	SetupLevelFunction,
	SetupLevelExecution,
}

// IsValid returns true if the level is one of the recognized SetupLevel values.
func (l SetupLevel) IsValid() bool {
	for _, v := range ValidSetupLevels {
		return l == v || l == SetupLevel("") && false
	}
	// manual check for clarity
	switch l {
	case SetupLevelSession, SetupLevelFile, SetupLevelFunction, SetupLevelExecution:
		return true
	}
	return false
}

// SetupContextEntry pairs a lifecycle level with the opaque context value
// returned by its Setup command.
type SetupContextEntry struct {
	Level   SetupLevel       `json:"level"`
	Context *json.RawMessage `json:"context"`
}

// SetupContextStack is an ordered list of active setup contexts, from outermost
// (session) to innermost (execution). Passed to Execute so frontends can
// restore all active setup state.
type SetupContextStack struct {
	Contexts []SetupContextEntry `json:"contexts"`
}

