// Package setup provides Go setup file execution for the Shatter protocol.
//
// Setup files are executed via subprocess (`go run`) and return an opaque
// JSON context value on stdout. The context is cached per level+scope so
// repeated Setup commands for the same scope reuse the cached value.
package setup

import (
	"encoding/json"
	"fmt"
	"os/exec"
	"strings"
	"sync"
	"time"
)

// DefaultTimeout for setup subprocess execution.
const DefaultTimeout = 30 * time.Second

// cacheKey uniquely identifies a setup context by level and scope.
type cacheKey struct {
	level string
	scope string
}

// Cache stores setup contexts keyed by (level, scope). Safe for concurrent access.
type Cache struct {
	mu      sync.Mutex
	entries map[cacheKey]json.RawMessage
}

// NewCache creates an empty setup context cache.
func NewCache() *Cache {
	return &Cache{
		entries: make(map[cacheKey]json.RawMessage),
	}
}

// Get retrieves a cached context for the given level and scope, if present.
func (c *Cache) Get(level, scope string) (json.RawMessage, bool) {
	c.mu.Lock()
	defer c.mu.Unlock()
	val, ok := c.entries[cacheKey{level: level, scope: scope}]
	return val, ok
}

// Put stores a context value for the given level and scope.
func (c *Cache) Put(level, scope string, ctx json.RawMessage) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.entries[cacheKey{level: level, scope: scope}] = ctx
}

// Evict removes the cached context for the given level and scope. Returns
// true if an entry was removed.
func (c *Cache) Evict(level, scope string) bool {
	c.mu.Lock()
	defer c.mu.Unlock()
	key := cacheKey{level: level, scope: scope}
	_, existed := c.entries[key]
	delete(c.entries, key)
	return existed
}

// EvictLevel removes all cached contexts at the given level. Returns the
// number of entries removed.
func (c *Cache) EvictLevel(level string) int {
	c.mu.Lock()
	defer c.mu.Unlock()
	count := 0
	for k := range c.entries {
		if k.level == level {
			delete(c.entries, k)
			count++
		}
	}
	return count
}

// Size returns the number of cached entries.
func (c *Cache) Size() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return len(c.entries)
}

// RunResult holds the output of a setup file execution.
type RunResult struct {
	Context json.RawMessage
}

// RunSetupFile executes a Go setup file via `go run` and captures the JSON
// context it prints to stdout. The setup file must print exactly one JSON
// value to stdout.
func RunSetupFile(file string, projectRoot string) (*RunResult, error) {
	args := []string{"run", file}

	cmd := exec.Command("go", args...)
	if projectRoot != "" {
		cmd.Dir = projectRoot
	}

	var stdout, stderr strings.Builder
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return nil, fmt.Errorf("setup file %q failed: %w\nstderr: %s", file, err, stderr.String())
	}

	output := strings.TrimSpace(stdout.String())
	if output == "" {
		// No output means the setup file produced no context; use null.
		return &RunResult{Context: json.RawMessage("null")}, nil
	}

	// Validate that the output is valid JSON.
	if !json.Valid([]byte(output)) {
		return nil, fmt.Errorf("setup file %q produced invalid JSON: %s", file, output)
	}

	return &RunResult{Context: json.RawMessage(output)}, nil
}

package setup

