func TestCacheGetPutRoundTrip(t *testing.T) {
	c := NewCache()
	ctx := json.RawMessage(`{"db":"conn_1"}`)
	c.Put("function", "myFunc", ctx)

	got, ok := c.Get("function", "myFunc")
	if !ok {
		t.Fatal("expected cache hit")
	}
	if string(got) != string(ctx) {
		t.Errorf("got %s, want %s", got, ctx)
	}
}

func TestCacheGetMiss(t *testing.T) {
	c := NewCache()
	_, ok := c.Get("session", "missing")
	if ok {
		t.Error("expected cache miss")
	}
}

func TestCacheEvict(t *testing.T) {
	c := NewCache()
	c.Put("file", "main.go", json.RawMessage(`{}`))

	if !c.Evict("file", "main.go") {
		t.Error("expected eviction to return true")
	}
	if c.Evict("file", "main.go") {
		t.Error("second eviction should return false")
	}
	if c.Size() != 0 {
		t.Errorf("size = %d, want 0", c.Size())
	}
}

func TestCacheEvictLevel(t *testing.T) {
	c := NewCache()
	c.Put("function", "foo", json.RawMessage(`1`))
	c.Put("function", "bar", json.RawMessage(`2`))
	c.Put("session", "global", json.RawMessage(`3`))

	removed := c.EvictLevel("function")
	if removed != 2 {
		t.Errorf("removed = %d, want 2", removed)
	}
	if c.Size() != 1 {
		t.Errorf("size = %d, want 1", c.Size())
	}
	if _, ok := c.Get("session", "global"); !ok {
		t.Error("session entry should still exist")
	}
}

func TestCacheSize(t *testing.T) {
	c := NewCache()
	if c.Size() != 0 {
		t.Errorf("initial size = %d, want 0", c.Size())
	}
	c.Put("session", "s1", json.RawMessage(`{}`))
	c.Put("file", "f1", json.RawMessage(`{}`))
	if c.Size() != 2 {
		t.Errorf("size = %d, want 2", c.Size())
	}
}

func TestCachePutOverwrites(t *testing.T) {
	c := NewCache()
	c.Put("function", "fn", json.RawMessage(`"old"`))
	c.Put("function", "fn", json.RawMessage(`"new"`))

	got, ok := c.Get("function", "fn")
	if !ok {
		t.Fatal("expected cache hit")
	}
	if string(got) != `"new"` {
		t.Errorf("got %s, want %q", got, `"new"`)
	}
	if c.Size() != 1 {
		t.Errorf("size = %d, want 1", c.Size())
	}
}

func TestRunSetupFileWithValidGoFile(t *testing.T) {
	dir := t.TempDir()

	// Create a minimal Go setup file that prints JSON to stdout.
	setupFile := filepath.Join(dir, "setup.go")
	src := `package main

import "fmt"

func main() {
	fmt.Print("{\"initialized\":true}")
}
`
	if err := os.WriteFile(setupFile, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	result, err := RunSetupFile(setupFile, dir)
	if err != nil {
		t.Fatalf("RunSetupFile: %v", err)
	}

	var parsed map[string]bool
	if err := json.Unmarshal(result.Context, &parsed); err != nil {
		t.Fatalf("unmarshal context: %v", err)
	}
	if !parsed["initialized"] {
		t.Errorf("expected initialized=true, got %v", parsed)
	}
}

func TestRunSetupFileWithEmptyOutput(t *testing.T) {
	dir := t.TempDir()

	setupFile := filepath.Join(dir, "setup.go")
	src := `package main

func main() {}
`
	if err := os.WriteFile(setupFile, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	result, err := RunSetupFile(setupFile, dir)
	if err != nil {
		t.Fatalf("RunSetupFile: %v", err)
	}
	if string(result.Context) != "null" {
		t.Errorf("context = %s, want null", result.Context)
	}
}

func TestRunSetupFileWithNonexistentFile(t *testing.T) {
	_, err := RunSetupFile("/nonexistent/setup.go", "")
	if err == nil {
		t.Error("expected error for nonexistent file")
	}
}

