func (h *Handler) handleSetup(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "setup command requires a file path"
		return resp
	}
	if req.Scope == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "setup command requires a scope"
		return resp
	}
	if !req.Level.IsValid() {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
		return resp
	}

	levelStr := string(req.Level)

	// Check cache first.
	if cached, ok := h.setupCache.Get(levelStr, req.Scope); ok {
		h.log.Debug("Setup cache hit", "level", levelStr, "scope", req.Scope)
		resp.Status = "setup"
		ctx := json.RawMessage(cached)
		resp.SetupContext = &ctx
		return resp
	}

	// Resolve project root from the request.
	projectRoot := ""
	if req.ProjectRoot != nil {
		projectRoot = *req.ProjectRoot
	}

	result, err := setup.RunSetupFile(req.File, projectRoot)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("setup failed: %v", err)
		return resp
	}

	// Cache the context for subsequent calls at the same level+scope.
	h.setupCache.Put(levelStr, req.Scope, result.Context)
	h.log.Debug("Setup executed and cached", "level", levelStr, "scope", req.Scope)

	resp.Status = "setup"
	ctx := json.RawMessage(result.Context)
	resp.SetupContext = &ctx
	return resp
}

func (h *Handler) handleTeardown(resp Response, req Request) Response {
	if req.Scope == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "teardown command requires a scope"
		return resp
	}
	if !req.Level.IsValid() {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
		return resp
	}

	levelStr := string(req.Level)
	h.setupCache.Evict(levelStr, req.Scope)
	h.log.Debug("Teardown evicted cache", "level", levelStr, "scope", req.Scope)

	resp.Status = "teardown_ack"
	return resp
}

