func TestSetupWithValidFileReturnsContext(t *testing.T) {
	dir := t.TempDir()
	setupFile := filepath.Join(dir, "setup.go")
	src := "package main\nimport \"fmt\"\nfunc main() { fmt.Print(`{\"ready\":true}`) }\n"
	if err := os.WriteFile(setupFile, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}
	req := reqJSON(30, "setup", fmt.Sprintf(`"file":"%s","scope":"myFunc","level":"function"`, setupFile))
	resp := sendRecv(t, req)
	if resp.Status != "setup" {
		t.Fatalf("status = %q, want setup (message: %s)", resp.Status, resp.Message)
	}
	if resp.SetupContext == nil {
		t.Fatal("setup_context should not be nil")
	}
	var ctx map[string]bool
	if err := json.Unmarshal(*resp.SetupContext, &ctx); err != nil {
		t.Fatalf("unmarshal setup_context: %v", err)
	}
	if !ctx["ready"] {
		t.Errorf("expected ready=true, got %v", ctx)
	}
}

