func TestSetupCachingReusesContext(t *testing.T) {
	// Run setup twice with the same scope/level — second call should use cache.
	dir := t.TempDir()
	setupFile := filepath.Join(dir, "setup.go")
	// This file writes a timestamp, but since it's cached, both responses should match.
	src := "package main\nimport \"fmt\"\nfunc main() { fmt.Print(`{\"cached\":true}`) }\n"
	if err := os.WriteFile(setupFile, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	setupReq := reqJSON(40, "setup", fmt.Sprintf(`"file":"%s","scope":"fn","level":"function"`, setupFile))
	setupReq2 := reqJSON(41, "setup", fmt.Sprintf(`"file":"%s","scope":"fn","level":"function"`, setupFile))
	teardownReq := reqJSON(42, "teardown", `"scope":"fn","level":"function"`)
	shutdownReq := reqJSON(43, "shutdown")

	responses := conversation(t, setupReq, setupReq2, teardownReq, shutdownReq)
	if len(responses) != 4 {
		t.Fatalf("got %d responses, want 4", len(responses))
	}
	if responses[0].Status != "setup" {
		t.Fatalf("response[0].status = %q, want setup (msg: %s)", responses[0].Status, responses[0].Message)
	}
	if responses[1].Status != "setup" {
		t.Fatalf("response[1].status = %q, want setup (msg: %s)", responses[1].Status, responses[1].Message)
	}
	// Both should return the same context
	if string(*responses[0].SetupContext) != string(*responses[1].SetupContext) {
		t.Errorf("cached context mismatch: %s vs %s", *responses[0].SetupContext, *responses[1].SetupContext)
	}
	if responses[2].Status != "teardown_ack" {
		t.Errorf("response[2].status = %q, want teardown_ack", responses[2].Status)
	}
}

