// TestPropertySetupRequestRoundTrip verifies that setup requests with all four
// levels serialize and deserialize correctly.
func TestPropertySetupRequestRoundTrip(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		level := genSetupLevel().Draw(t, "level")
		scope := genIdent().Draw(t, "scope")
		file := genIdent().Draw(t, "file") + ".go"

		req := Request{
			ProtocolVersion: ProtocolVersion,
			ID:              rapid.IntRange(1, 1000).Draw(t, "id"),
