			File:            file,
			Scope:           scope,
			Level:           level,
		}

		data, err := json.Marshal(req)
		if err != nil {
			t.Fatalf("marshal: %v", err)
		}
		var decoded Request
		if err := json.Unmarshal(data, &decoded); err != nil {
			t.Fatalf("unmarshal: %v", err)
		}
		if decoded.Command != "setup" {
			t.Fatalf("command: got %q, want setup", decoded.Command)
