// FuzzSetupRequestDeserialize fuzzes setup request deserialization, covering
// the new SetupLevel, scope, and parent_context fields.
func FuzzSetupRequestDeserialize(f *testing.F) {
	seeds := []string{
		`{"protocol_version":"0.1.0","id":1,"command":"setup","file":"s.go","scope":"fn1","level":"function"}`,
		`{"protocol_version":"0.1.0","id":2,"command":"setup","file":"s.go","scope":"global","level":"session","parent_context":{"contexts":[]}}`,
		`{"protocol_version":"0.1.0","id":3,"command":"setup","file":"s.go","scope":"fn","level":"execution","parent_context":{"contexts":[{"level":"session","context":{"db":1}}]}}`,
		`{"protocol_version":"0.1.0","id":4,"command":"teardown","scope":"fn1","level":"function"}`,
		`{"protocol_version":"0.1.0","id":5,"command":"teardown","scope":"global","level":"session"}`,
		`{"protocol_version":"0.1.0","id":6,"command":"setup","file":"s.go","scope":"","level":""}`,
		`{"protocol_version":"0.1.0","id":7,"command":"setup"}`,
		`{}`,
	}

	for _, s := range seeds {
		f.Add([]byte(s))
	}

	f.Fuzz(func(t *testing.T, data []byte) {
		var req Request
		if err := json.Unmarshal(data, &req); err != nil {
			return
		}
		// Re-marshal and re-unmarshal must not panic.
		remarshaled, err := json.Marshal(req)
		if err != nil {
			return
		}
		var req2 Request
		json.Unmarshal(remarshaled, &req2) //nolint:errcheck
	})
}

// FuzzSetupContextStackDeserialize fuzzes the SetupContextStack type which
// contains nested SetupContextEntry values.
func FuzzSetupContextStackDeserialize(f *testing.F) {
	seeds := []string{
		`{"contexts":[]}`,
		`{"contexts":[{"level":"session","context":null}]}`,
		`{"contexts":[{"level":"function","context":{"db":"conn"}},{"level":"session","context":42}]}`,
		`{"contexts":[{"level":"file","context":[1,2,3]}]}`,
		`{}`,
		`null`,
	}

	for _, s := range seeds {
		f.Add([]byte(s))
	}

	f.Fuzz(func(t *testing.T, data []byte) {
		var stack SetupContextStack
		if err := json.Unmarshal(data, &stack); err != nil {
			return
		}
		remarshaled, err := json.Marshal(stack)
		if err != nil {
			return
		}
		var stack2 SetupContextStack
		json.Unmarshal(remarshaled, &stack2) //nolint:errcheck
	})
}
